def assess(record: dict) -> str:
    required = {'json_schema', 'extra_policy', 'business_rule', 'case_id', 'valid_fixture'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + missing[0]
    meets = not (record["extra_policy"] == "allow" and not record["business_rule"])
    return "PASS" if meets else 'REJECT_SCHEMA'

